"        # Add syllabus-anchor class to the last opening <p> tag in new_preceding\n        p_matches = list(_re.finditer(r'<p(?:\\s+class=\"([^\"]*)\")?>', new_preceding))\n        if p_matches:\n            last_p = p_matches[-1]\n            start_idx, end_idx = last_p.span()\n            cls_val = last_p.group(1)\n            if cls_val:\n                new_tag = f'<p class=\"{cls_val} syllabus-anchor\">'\n            else:\n                new_tag = '<p class=\"syllabus-anchor\">'\n            new_preceding = new_preceding[:start_idx] + new_tag + new_preceding[end_idx:]"